import { Navigate, useLocation } from "react-router-dom";
import { useEffect, useState } from "react";

export default function ProtectedRoute({ children, allowedRoles = [], allowUnauthenticated = false }) {
  const [isAuthenticated, setIsAuthenticated] = useState(null);
  const [userRole, setUserRole] = useState(null);
  const location = useLocation();

  useEffect(() => {
    // Check authentication status
    const token = localStorage.getItem("access_token");
    const role = localStorage.getItem("role");
    
    setIsAuthenticated(!!token);
    setUserRole(role);
  }, []);

  // Show loading while checking
  if (isAuthenticated === null) {
    return (
      <div style={{
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        height: "100vh",
        background: "#0a0a0a",
        color: "#c89d5c"
      }}>
        <div className="loading-spinner">Loading...</div>
      </div>
    );
  }

  // If allowUnauthenticated is true, allow access to non-authenticated users
  if (allowUnauthenticated && !isAuthenticated) {
    return children;
  }

  // Not authenticated - redirect to staff login
  if (!isAuthenticated) {
    return <Navigate to="/staff-login" state={{ from: location }} replace />;
  }

  // Check role authorization - redirect admin/staff away from customer pages
  if (allowedRoles.length > 0) {
    // If user is admin and trying to access customer-only page
    if (userRole === "admin") {
      return <Navigate to="/admin" replace />;
    }
    // If user is staff and trying to access customer-only page
    if (userRole === "staff") {
      return <Navigate to="/staff" replace />;
    }
    // If allowedRoles doesn't include the user's role (or is empty for customer-only)
    if (!allowedRoles.includes(userRole)) {
      return <Navigate to="/" replace />;
    }
  }

  return children;
}
